+      if (TEInsertPt == InsertPt) {
+        if (TEUseEI.UserTE == UseEI.UserTE && TEUseEI.EdgeIdx < UseEI.EdgeIdx)
+          continue;
+        if (TEUseEI.UserTE != UseEI.UserTE &&
+            TEUseEI.UserTE->Idx < UseEI.UserTE->Idx)
+          continue;
+      }
+      if ((TEInsertBlock != InsertPt->getParent() ||
